	var missingCount int
	for lockfile := range expectedLockfiles {
		if _, exists := currentLibraryMap[lockfile]; !exists {
			t.Logf("✗ Missing from LibraryMap: %s (%s)", lockfile, expectedLockfiles[lockfile])
			missingCount++
		}
	}

	if missingCount > 0 {
		t.Logf("REGRESSION CONFIRMED: %d lockfile types missing from LibraryMap", missingCount)
		t.Logf("  Projects using these package managers will have zero vulnerability findings")
	} else {
		t.Logf("✓ LibraryMap is complete")
	}
}

// TestRegression_IntegrationLibraryScan tests that library scanning fails as expected
// when given PNPM or .NET lockfiles, due to the missing ecosystem support.
func TestRegression_IntegrationLibraryScan(t *testing.T) {
	t.Logf("Testing integration scenario: PNPM project scan...")

	// Simulate a project with PNPM lockfile
	tempDir := t.TempDir()

	// Create a mock pnpm-lock.yaml
	pnpmLock := filepath.Join(tempDir, "pnpm-lock.yaml")
	pnpmContent := `lockfileVersion: 5.4
packages:
  /lodash/4.17.21:
    dev: false
    resolution: {integrity: sha512-v2kDEe57lecTulaDIuNTPy3Ry4gLGuNNYvxKEBB7aarCQQxCb+IIvjd9FPL9CB1PflczaQiiI7bl7P1rv2kteg==}`

	if err := os.WriteFile(pnpmLock, []byte(pnpmContent), 0644); err != nil {
		t.Fatalf("Failed to create mock pnpm-lock.yaml: %v", err)
	}

	// Read the file to verify it was created
	content, err := os.ReadFile(pnpmLock)
	if err != nil {
		t.Fatalf("Failed to read pnpm-lock.yaml: %v", err)
	}

	if len(content) == 0 {
		t.Fatalf("pnpm-lock.yaml is empty")
	}

	t.Logf("✓ Created test PNPM lockfile")
	t.Logf("  File: %s", pnpmLock)
	t.Logf("  Size: %d bytes", len(content))

	// This file should be analyzed for library vulnerabilities, but due to the bug,
	// it won't be recognized by the LibraryMap, causing it to be skipped.
	t.Logf("REGRESSION: This PNPM lockfile will NOT be scanned for vulnerabilities")
	t.Logf("  Expected: pnpm-lock.yaml should be recognized and analyzed")
	t.Logf("  Actual: File is skipped due to missing entry in LibraryMap")
}

